    const unsubscribe = onSnapshot(gameDocRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data() as Partial<GameState>;
        const serverPlayers = data.players || [];
        setGameState(prev => ({
          ...prev,
          ...data,
          players: serverPlayers,
          gridData: data.gridData || {},
          sentences: data.sentences || TOPIC_TEMPLATES.topic1.sentences,
          dicePrompts: data.dicePrompts || [], 
          gameTitle: data.gameTitle || TOPIC_TEMPLATES.topic1.title,
          currentTurnIndex: typeof data.currentTurnIndex === 'number' ? data.currentTurnIndex : 0,
          diceValue: data.diceValue || 1,
          isRolling: data.isRolling || false,
          revealedCells: data.revealedCells || {}
        }));

        setDisplayPlayers(prevDisplayPlayers => {
            if (serverPlayers.length < prevDisplayPlayers.length) return serverPlayers; 
            if (prevDisplayPlayers.length === 0) return serverPlayers;

            const newDisplayPlayers = [...prevDisplayPlayers];
            let hasChanges = false;

            serverPlayers.forEach((serverPlayer, index) => {
                if (!newDisplayPlayers[index]) {
                    newDisplayPlayers[index] = serverPlayer;
                    hasChanges = true;
                    return;
                }
                const currentDisplayPos = newDisplayPlayers[index].position;
                const targetPos = serverPlayer.position;
                if (currentDisplayPos !== targetPos) {
                    hasChanges = true;
                    newDisplayPlayers[index] = { ...serverPlayer, position: currentDisplayPos };
                } else {
                      newDisplayPlayers[index] = serverPlayer;
                      hasChanges = true;
                }
            });
            return hasChanges ? newDisplayPlayers : prevDisplayPlayers;
        });
      } else {
        // Init with default topic 1
        const initialGridData: Record<string, GridCellData> = {};
        GRID_LAYOUT_BASE.forEach(item => {
           const topicData = TOPIC_TEMPLATES.topic1.gridData[item.id] || {};
           initialGridData[item.id] = {
               label: topicData.label || "...",
               color: item.defaultColor,
               textColor: item.textColor,
               image: topicData.image || '',
               sound: ''
           };
        });

        // 嘗試初始化 DB，如果權限不足(例如沒登入)可能會失敗，這裡 catch 起來不影響 UI
        setDoc(gameDocRef, {
          players: [],
          gridData: initialGridData,
          sentences: TOPIC_TEMPLATES.topic1.sentences,
          dicePrompts: TOPIC_TEMPLATES.topic1.dicePrompts || [],
          gameTitle: TOPIC_TEMPLATES.topic1.title,
          currentTurnIndex: 0,
          diceValue: 1,
          isRolling: false,
          lastActionTimestamp: Date.now(),
          revealedCells: {}
        }, { merge: true }).catch(e => console.warn("Init DB Skipped/Failed:", e));
      }
    }, (error) => {
        // 處理 Snapshot 錯誤 (例如權限不足)
        console.error("Firestore Error:", error);
    });
    return () => unsubscribe();
  }, [user]);

