                  if (currentPos !== targetPos) {
                      let nextPos = (currentPos + 1) % PATH_ORDER.length;
                      nextPlayers[index] = { ...nextPlayers[index], position: nextPos };
                      updated = true;
                      if (stepAudioRef.current) {
