                        {playersHere.map(p => <div key={p.id} className="player-token" style={{backgroundColor: p.color}} title={p.name}></div>)}
                     </div>
                   </div>
                 );
               })}

               {/* Center Control */}
               <div className="grid-center">
                  <div className={`w-full max-w-xs rounded-xl p-4 mb-4 shadow-lg text-center relative group transition-colors duration-300 ${getSentenceStyle(currentSentenceIndex)}`} onClick={() => { if(isEditing) setEditingSentenceIndex(currentSentenceIndex); }}>
                      {isEditing && <div className="absolute top-1 right-1 bg-white/30 p-1 rounded-full cursor-pointer hover:bg-white/50"><Edit3 className="w-4 h-4 text-white"/></div>}
                      <div className="text-white/80 text-sm mb-2 font-bold uppercase tracking-wider border-b border-white/20 pb-1">句型練習 ({gameState.sentences.length > 0 ? currentSentenceIndex + 1 : 0}/{gameState.sentences.length})</div>
                      <div className="flex items-center justify-between">
                          <button onClick={(e) => { e.stopPropagation(); toggleSentence('prev'); }} className="text-white/50 hover:text-white transition-colors p-1"><ChevronLeft className="w-8 h-8" /></button>
                          <div className="text-white font-bold text-xl md:text-2xl px-2 min-h-[4rem] flex items-center justify-center drop-shadow-md leading-tight">{gameState.sentences[currentSentenceIndex]}</div>
                          <button onClick={(e) => { e.stopPropagation(); toggleSentence('next'); }} className="text-white/50 hover:text-white transition-colors p-1"><ChevronRight className="w-8 h-8" /></button>
                      </div>

                      <div className="grid grid-cols-2 gap-2 mt-3 pt-2 border-t border-white/20 w-full">
                          <select className="bg-teal-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-teal-500 transition-colors appearance-none text-center font-bold" value={selectedNumber} onChange={(e) => setSelectedNumber(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">數字</option>
                               {NUMBER_SET.map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                          <select className="bg-rose-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-rose-500 transition-colors appearance-none text-center font-bold" value={selectedGenitive} onChange={(e) => setSelectedGenitive(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">屬格代名詞</option>
                               {GENITIVE_PRONOUNS.map(p => <option key={p} value={p}>{p}</option>)}
                          </select>
                          <select className="bg-indigo-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-indigo-500 transition-colors appearance-none text-center font-bold" value={selectedNominative} onChange={(e) => setSelectedNominative(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">主格代名詞</option>
                               {NOMINATIVE_PRONOUNS.map(p => <option key={p} value={p}>{p}</option>)}
                          </select>
                          <select className="bg-amber-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-amber-500 transition-colors appearance-none text-center font-bold" value={selectedPeopleCount} onChange={(e) => setSelectedPeopleCount(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">人數</option>
                               {PEOPLE_COUNT_SET.map(p => <option key={p} value={p}>{p}</option>)}
                          </select>
                      </div>
                  </div>
                  <div className="mb-4 relative w-20 h-20 md:w-24 md:h-24 flex items-center justify-center cursor-pointer" onClick={rollDice}>
                      <div className="absolute -top-3 -right-12 bg-yellow-400 text-amber-900 px-3 py-1 rounded-sm font-bold shadow-md transform rotate-12 z-20 border-2 border-white text-sm whitespace-nowrap animate-bounce" style={{animationDuration: '2s'}}>{currentDicePrompt}</div>
                      <div className={`dice-3d w-full h-full bg-orange-100 rounded-xl border-4 border-amber-800 flex items-center justify-center shadow-lg ${gameState.isRolling ? 'rolling' : ''}`}>
                          <div className="grid grid-cols-3 grid-rows-3 gap-1 p-3 w-full h-full">
                              {[...Array(9)].map((_, i) => {
                                  const val = gameState.diceValue;
                                  let show = false;
                                  if (i === 4 && (val === 1 || val === 3 || val === 5)) show = true;
                                  if ((i === 0 || i === 8) && (val > 1)) show = true;
                                  if ((i === 2 || i === 6) && (val > 3)) show = true;
                                  if ((i === 3 || i === 5) && (val === 6)) show = true;
                                  return <div key={i} className="flex items-center justify-center">{show && <div className="w-3 h-3 md:w-4 md:h-4 bg-amber-900 rounded-full"></div>}</div>;
                              })}
                          </div>
                      </div>
                  </div>
                  <button onClick={rollDice} disabled={gameState.isRolling} className={`px-6 py-2 rounded-full text-base font-bold shadow-lg transform transition-all whitespace-nowrap ${gameState.isRolling ? 'bg-gray-500 cursor-not-allowed scale-95' : 'bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 text-white hover:scale-105 active:scale-95'}`}>{gameState.isRolling ? '...' : '擲骰子'}</button>
                  <div className="mt-6 flex gap-4"><button onClick={confirmResetGame} className="text-gray-400 hover:text-white flex items-center gap-1 text-sm bg-black/20 px-3 py-1 rounded-full transition-colors"><RotateCcw className="w-3 h-3"/> 重置遊戲</button></div>
               </div>
            </div>
        </div>
      ) : (
        /* Login Screen */
        <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md text-center border-t-8 border-amber-500 relative animate-in fade-in zoom-in duration-300">
             <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-slate-100 overflow-hidden"><img src="https://res.cloudinary.com/dm1ksvptk/image/upload/v1749659604/vxem1akzssudvs0neffn.png" alt="Logo" className="w-full h-full object-cover"/></div>
             <h2 className="text-2xl font-bold text-gray-800 mb-1">歡迎來到族語大富翁</h2>
             <p className="text-gray-500 mb-4 font-medium">{TOPIC_TEMPLATES[selectedTopicId]?.title || gameState.gameTitle || "馬蘭阿美語"}</p>

             <div className="mb-6 flex flex-col items-center justify-center bg-gray-50 p-4 rounded-xl border border-dashed border-gray-300"><img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=https://example.com/game`} alt="Scan to join" className="w-32 h-32 mb-2 opacity-80"/><span className="text-xs text-gray-500 flex items-center gap-1"><QrCode className="w-3 h-3"/> 掃描加入遊戲 (學生用)</span></div>
             <div className="border-t border-gray-200 my-4 pt-4">
                <p className="text-sm font-bold text-gray-600 mb-3 flex items-center justify-center gap-1"><Settings className="w-4 h-4"/> 教師設定區</p>

                <div className="mb-3 text-left">
                    <label className="text-xs font-bold text-gray-500 mb-1 block pl-1">選擇課程主題 (自動更新標題與單字)</label>
                    <div className="relative">
                        <select 
                            value={selectedTopicId} 
                            onChange={(e) => setSelectedTopicId(e.target.value)}
                            className="w-full p-2 pl-9 bg-slate-50 border border-slate-200 rounded-lg text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500"
                        >
                            <option value="topic1">1. 生活會話篇 第11課 (兄弟姊妹)</option>
                            <option value="topic2">2. 第5階-9課 riyal 海</option>
                            <option value="topic3">3. 情境族語 第 10課 適品買賣</option>
                            <option value="topic4">4. 族語期末檢測</option>
                        </select>
                        <BookOpen className="w-4 h-4 text-gray-400 absolute left-3 top-2.5 pointer-events-none"/>
                    </div>
                </div>

                <div className="flex gap-2 mb-4">
                    <button onClick={confirmDemoTeams} className="flex-1 bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"><Zap className="fill-current w-5 h-5" /> 演示模式</button>
                    <button onClick={() => setShowSetupModal(true)} className="flex-1 bg-teal-600 text-white font-bold py-3 rounded-xl shadow-lg hover:bg-teal-700 transition-all flex items-center justify-center gap-2"><PenTool className="fill-current w-5 h-5" /> 手動名單</button>
                </div>
             </div>
             <div className="relative flex py-2 items-center"><div className="flex-grow border-t border-gray-300"></div><span className="flex-shrink-0 mx-4 text-gray-400 text-xs">或單獨加入 (最多7組)</span><div className="flex-grow border-t border-gray-300"></div></div>
             <div className="mb-4 mt-2"><input type="text" placeholder="輸入隊伍名稱" className="w-full text-center text-lg border-2 border-gray-200 rounded-xl p-3 focus:border-amber-500 outline-none" value={localPlayerName} onChange={e => setLocalPlayerName(e.target.value)} onKeyDown={e => e.key === 'Enter' && joinGame()}/></div>
             <div className="flex flex-col gap-2">
                <button onClick={joinGame} disabled={!localPlayerName.trim()} className="w-full bg-amber-500 text-white text-xl font-bold py-3 rounded-xl shadow-lg hover:bg-amber-600 disabled:opacity-50 transition-all flex items-center justify-center gap-2"><Play className="fill-current w-5 h-5" /> 開始遊戲</button>
                {gameState.players.length > 0 && (
                    <button onClick={confirmForceResetRoom} className="w-full bg-red-100 text-red-600 text-sm font-bold py-2 rounded-xl hover:bg-red-200 transition-all flex items-center justify-center gap-2">
                        <RotateCcw className="w-4 h-4" /> 強制重置房間 (清除卡住的舊遊戲)
                    </button>
                )}
             </div>
             <p className="mt-4 text-xs text-gray-400">目前已有 {gameState.players.length} 組玩家加入</p>
        </div>
      )}

      {/* Modals */}
      {isEditing && selectedCell && <EditModal selectedCell={selectedCell} onClose={() => setSelectedCell(null)} onSave={updateGridCell} />}
      {isEditing && editingSentenceIndex !== null && gameState.sentences && <SentenceEditModal index={editingSentenceIndex} sentence={gameState.sentences[editingSentenceIndex]} onClose={() => setEditingSentenceIndex(null)} onSave={updateSentence} />}
      {showPlayerModal && <PlayerListModal players={gameState.players} onClose={() => setShowPlayerModal(false)} onUpdatePlayers={updatePlayersList} />}
      {showSetupModal && <PlayerListModal players={[]} onClose={() => setShowSetupModal(false)} onUpdatePlayers={startCustomGame} title="手動建立名單 (教師用)" confirmLabel="建立並開始遊戲" />}

      {/* Global Dialog */}
      <Dialog 
        isOpen={dialogConfig.isOpen}
        title={dialogConfig.title}
        message={dialogConfig.message}
        type={dialogConfig.type}
        data={dialogConfig.data}
        onConfirm={dialogConfig.onConfirm}
        onCancel={() => setDialogConfig(prev => ({...prev, isOpen: false}))}
      />
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
