  const bgmRef = useRef<HTMLAudioElement>(null);

  // --- Initialization ---
  useEffect(() => {
    const initAuth = async () => {
      try {
        // @ts-ignore
        if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) {
          // @ts-ignore
          await signInWithCustomToken(auth, __initial_auth_token);
        } else {
          await signInAnonymously(auth);
        }
      } catch (error: any) {
        console.error("Auth Error:", error);
        if (error.code === 'auth/configuration-not-found' || error.code === 'auth/operation-not-allowed' || error.code === 'auth/internal-error') {
            console.warn("⚠️ Auth disabled or misconfigured. Switching to fallback mode.");
            const fallbackUid = localStorage.getItem('monopoly_fallback_uid') || `guest-${Date.now()}`;
            localStorage.setItem('monopoly_fallback_uid', fallbackUid);
            setUser({ uid: fallbackUid, isAnonymous: true } as FirebaseUser);
        }
      }
    };
    initAuth();
    const unsubscribeAuth = onAuthStateChanged(auth, (u) => {
        if (u) setUser(u);
    });
    return () => unsubscribeAuth();
  }, []);

  // Data Sync
  useEffect(() => {
    if (!user) return;
    const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);

    const unsubscribe = onSnapshot(gameDocRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data() as Partial<GameState>;
        const serverPlayers = data.players || [];
        setGameState(prev => ({
          ...prev,
          ...data,
          players: serverPlayers,
          gridData: data.gridData || {},
          sentences: data.sentences || TOPIC_TEMPLATES.topic1.sentences,
          dicePrompts: data.dicePrompts || [], 
          gameTitle: data.gameTitle || TOPIC_TEMPLATES.topic1.title,
          currentTurnIndex: typeof data.currentTurnIndex === 'number' ? data.currentTurnIndex : 0,
          diceValue: data.diceValue || 1,
          isRolling: data.isRolling || false,
          revealedCells: data.revealedCells || {}
        }));

        setDisplayPlayers(prevDisplayPlayers => {
            if (serverPlayers.length < prevDisplayPlayers.length) return serverPlayers; 
            if (prevDisplayPlayers.length === 0) return serverPlayers;

            const newDisplayPlayers = [...prevDisplayPlayers];
            let hasChanges = false;

            serverPlayers.forEach((serverPlayer, index) => {
                if (!newDisplayPlayers[index]) {
                    newDisplayPlayers[index] = serverPlayer;
                    hasChanges = true;
                    return;
                }
                const currentDisplayPos = newDisplayPlayers[index].position;
                const targetPos = serverPlayer.position;
                if (currentDisplayPos !== targetPos) {
                    hasChanges = true;
                    newDisplayPlayers[index] = { ...serverPlayer, position: currentDisplayPos };
                } else {
                      newDisplayPlayers[index] = serverPlayer;
                      hasChanges = true;
                }
            });
            return hasChanges ? newDisplayPlayers : prevDisplayPlayers;
        });
      } else {
         // Initial data structure setup (handled by actions now)
      }
    }, (error) => {
        console.error("Firestore Error (Snapshot):", error);
    });
    return () => unsubscribe();
  }, [user]);

  // Animation Loop
  useEffect(() => {
