          ...prev,
          revealedCells: { ...prev.revealedCells, [cellId]: !prev.revealedCells[cellId] }
      }));

      try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        const currentStatus = gameState.revealedCells[cellId] || false;
        await setDoc(gameDocRef, {
            revealedCells: {
                ...gameState.revealedCells,
                [cellId]: !currentStatus
            }
        }, { merge: true });
      } catch (e) { console.error("Reveal Error (Local fallback used):", e); }
  };

  const toggleRevealAll = async () => {
      const allCellIds = GRID_LAYOUT_BASE.map(c => c.id);
      const allRevealed = allCellIds.every(id => gameState.revealedCells[id]);
      const newRevealedState: Record<string, boolean> = {};
      if (!allRevealed) {
          allCellIds.forEach(id => newRevealedState[id] = true);
      }

      // Optimistic
      setGameState(prev => ({ ...prev, revealedCells: newRevealedState }));

      try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        await updateDoc(gameDocRef, { 
            revealedCells: newRevealedState
        });
      } catch (e) { console.error("Toggle Reveal All Error (Local fallback used):", e); }
