export default function MonopolyGame() {
  const [user, setUser] = useState<FirebaseUser | null>(null);
  const [gameState, setGameState] = useState<GameState>({
    players: [],
    gridData: {},
    sentences: TOPIC_TEMPLATES.topic1.sentences,
    dicePrompts: [], 
    gameTitle: TOPIC_TEMPLATES.topic1.title,
    currentTurnIndex: 0,
    diceValue: 1,
    isRolling: false,
    lastActionTimestamp: 0,
    revealedCells: {} 
  });

  const [displayPlayers, setDisplayPlayers] = useState<Player[]>([]);
  const [localPlayerName, setLocalPlayerName] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [showPlayerModal, setShowPlayerModal] = useState(false);
  const [showSetupModal, setShowSetupModal] = useState(false);
  const [selectedCell, setSelectedCell] = useState<({ id: string } & GridCellData) | null>(null);
  const [editingSentenceIndex, setEditingSentenceIndex] = useState<number | null>(null);
  const [currentSentenceIndex, setCurrentSentenceIndex] = useState(0);

  const [selectedTopicId, setSelectedTopicId] = useState('topic1');
  const [selectedNumber, setSelectedNumber] = useState('');
  const [selectedNominative, setSelectedNominative] = useState('');
  const [selectedGenitive, setSelectedGenitive] = useState('');
  const [selectedPeopleCount, setSelectedPeopleCount] = useState('');

  const [dialogConfig, setDialogConfig] = useState<DialogConfig>({ isOpen: false, title: '', message: '', type: 'confirm' });

  const audioRef = useRef<HTMLAudioElement>(null);
  const stepAudioRef = useRef<HTMLAudioElement>(null); 
  const bgmRef = useRef<HTMLAudioElement>(null);

  // --- Initialization ---
  useEffect(() => {
    const initAuth = async () => {
      try {
        // @ts-ignore
        if (typeof __initial_auth_token !== 'undefined' && __initial_auth_token) {
          // @ts-ignore
          await signInWithCustomToken(auth, __initial_auth_token);
        } else {
          await signInAnonymously(auth);
        }
      } catch (error: any) {
        // Only log actual unexpected errors, suppress known configuration missing errors
        const isConfigError = error.code === 'auth/configuration-not-found' || 
                              error.code === 'auth/operation-not-allowed' || 
                              error.code === 'auth/internal-error' ||
                              error.code === 'auth/admin-restricted-operation';

        if (isConfigError) {
            console.warn("⚠️ Firebase Auth not configured. Switching to offline guest mode.");
            const fallbackUid = localStorage.getItem('monopoly_fallback_uid') || `guest-${Date.now()}`;
            localStorage.setItem('monopoly_fallback_uid', fallbackUid);
            setUser({ uid: fallbackUid, isAnonymous: true } as FirebaseUser);
        } else {
            console.error("Auth Error:", error);
        }
      }
    };
    initAuth();
    const unsubscribeAuth = onAuthStateChanged(auth, (u) => {
        if (u) setUser(u);
    });
    return () => unsubscribeAuth();
  }, []);

  // Data Sync
  useEffect(() => {
    if (!user) return;
    const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);

    const unsubscribe = onSnapshot(gameDocRef, (docSnap) => {
      if (docSnap.exists()) {
        const data = docSnap.data() as Partial<GameState>;
        const serverPlayers = data.players || [];
        setGameState(prev => ({
          ...prev,
          ...data,
          players: serverPlayers,
          gridData: data.gridData || {},
          sentences: data.sentences || TOPIC_TEMPLATES.topic1.sentences,
          dicePrompts: data.dicePrompts || [], 
          gameTitle: data.gameTitle || TOPIC_TEMPLATES.topic1.title,
          currentTurnIndex: typeof data.currentTurnIndex === 'number' ? data.currentTurnIndex : 0,
          diceValue: data.diceValue || 1,
          isRolling: data.isRolling || false,
          revealedCells: data.revealedCells || {}
        }));

        setDisplayPlayers(prevDisplayPlayers => {
            if (serverPlayers.length < prevDisplayPlayers.length) return serverPlayers; 
            if (prevDisplayPlayers.length === 0) return serverPlayers;

            const newDisplayPlayers = [...prevDisplayPlayers];
            let hasChanges = false;

            serverPlayers.forEach((serverPlayer, index) => {
                if (!newDisplayPlayers[index]) {
                    newDisplayPlayers[index] = serverPlayer;
                    hasChanges = true;
                    return;
                }
                const currentDisplayPos = newDisplayPlayers[index].position;
                const targetPos = serverPlayer.position;
                if (currentDisplayPos !== targetPos) {
                    hasChanges = true;
                    newDisplayPlayers[index] = { ...serverPlayer, position: currentDisplayPos };
                } else {
                      newDisplayPlayers[index] = serverPlayer;
                      hasChanges = true;
                }
            });
            return hasChanges ? newDisplayPlayers : prevDisplayPlayers;
        });
      } else {
         // Initial data structure setup (handled by actions now)
      }
    }, (error) => {
        // Silently fail on snapshot errors in offline mode
        if (error.code !== 'permission-denied') {
             console.error("Firestore Error (Snapshot):", error);
        }
    });
    return () => unsubscribe();
  }, [user]);

  // Animation Loop
  useEffect(() => {
      if (gameState.players.length === 0) return;
      const moveInterval = setInterval(() => {
          setDisplayPlayers(prev => {
              const nextPlayers = [...prev];
              let updated = false;
              gameState.players.forEach((targetPlayer, index) => {
                  if (!nextPlayers[index]) return;
                  const currentPos = nextPlayers[index].position;
                  const targetPos = targetPlayer.position;
                  if (currentPos !== targetPos) {
                      let nextPos = (currentPos + 1) % PATH_ORDER.length;
                      nextPlayers[index] = { ...nextPlayers[index], position: nextPos };
                      updated = true;
                      if (stepAudioRef.current) {
                          stepAudioRef.current.currentTime = 0;
                          stepAudioRef.current.play().catch(() => {});
                      }
                  }
              });
              return updated ? nextPlayers : prev;
          });
      }, 400);
      return () => clearInterval(moveInterval);
  }, [gameState.players]);

  // Actions
  const playSound = (url?: string) => {
    if (!url) return;
    if (audioRef.current) {
      audioRef.current.src = url;
      audioRef.current.play().catch(e => console.log("Audio play error", e));
    }
  };

  const playBGM = () => {
     if (bgmRef.current) {
        if (bgmRef.current.paused) {
            bgmRef.current.volume = 0.3;
            bgmRef.current.play().catch(e => console.log("BGM play error", e));
        } else {
            bgmRef.current.pause();
        }
     }
  };

  const toggleCellReveal = async (cellId: string) => {
      // Optimistic Update
      setGameState(prev => ({
          ...prev,
          revealedCells: { ...prev.revealedCells, [cellId]: !prev.revealedCells[cellId] }
      }));

      try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        const currentStatus = gameState.revealedCells[cellId] || false;
        await setDoc(gameDocRef, {
            revealedCells: {
                ...gameState.revealedCells,
                [cellId]: !currentStatus
            }
        }, { merge: true });
      } catch (e) { /* Ignore offline errors */ }
  };

  const toggleRevealAll = async () => {
      const allCellIds = GRID_LAYOUT_BASE.map(c => c.id);
      const allRevealed = allCellIds.every(id => gameState.revealedCells[id]);
      const newRevealedState: Record<string, boolean> = {};
      if (!allRevealed) {
          allCellIds.forEach(id => newRevealedState[id] = true);
      }

      // Optimistic
      setGameState(prev => ({ ...prev, revealedCells: newRevealedState }));

      try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        await updateDoc(gameDocRef, { 
            revealedCells: newRevealedState
        });
      } catch (e) { /* Ignore offline errors */ }
  };

  const joinGame = async () => {
    if (!user || !localPlayerName.trim()) return;

    const currentPlayerCount = gameState.players.length;
    const colorIndex = currentPlayerCount % PLAYER_COLORS.length;
    const assignedColor = PLAYER_COLORS[colorIndex].value;
    const newPlayer: Player = { id: user.uid, name: localPlayerName, color: assignedColor, position: 0, score: 0 };

    // Local Fallback Logic
    const applyLocalJoin = () => {
        setGameState(prev => {
             const existing = prev.players.find(p => p.id === user.uid);
             if (existing) return prev;

             let newState = { ...prev, players: [...prev.players, newPlayer] };

             if (prev.players.length === 0) {
                const template = TOPIC_TEMPLATES[selectedTopicId];
                const newGridData: Record<string, GridCellData> = {};
                GRID_LAYOUT_BASE.forEach(item => {
                    const topicData = template.gridData[item.id] || {};
                    newGridData[item.id] = {
                        label: topicData.label || "...",
                        color: item.defaultColor,
                        textColor: item.textColor,
                        image: topicData.image || '',
                        sound: ''
                    };
                });
                newState = {
                    ...newState,
                    gridData: newGridData,
                    sentences: template.sentences,
                    dicePrompts: template.dicePrompts || [],
                    gameTitle: template.title,
                };
             }
             return newState;
        });
    };

    try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        const shouldUpdateTopic = gameState.players.length === 0;

        let updateData: any = {
            players: arrayUnion(newPlayer)
        };

        if (shouldUpdateTopic) {
            const template = TOPIC_TEMPLATES[selectedTopicId];
            const newGridData: Record<string, GridCellData> = {};
            GRID_LAYOUT_BASE.forEach(item => {
               const topicData = template.gridData[item.id] || {};
               newGridData[item.id] = {
                   label: topicData.label || "...",
                   color: item.defaultColor,
                   textColor: item.textColor,
                   image: topicData.image || '',
                   sound: ''
               };
            });

            updateData = {
                ...updateData,
                gridData: newGridData,
                sentences: template.sentences,
                dicePrompts: template.dicePrompts || [], 
                gameTitle: template.title,
                revealedCells: {} 
            };
        }

        const existingPlayer = gameState.players.find(p => p.id === user.uid);
        if (!existingPlayer) {
            await setDoc(gameDocRef, updateData, { merge: true });
        }
    } catch(e) { 
        console.warn("Join Error (Using local logic):", e); 
        applyLocalJoin();
    }
  };

  const confirmDemoTeams = () => {
      if (!user) return;
      const topicTitle = TOPIC_TEMPLATES[selectedTopicId].title;
      setDialogConfig({
          isOpen: true,
          title: '建立演示團隊',
          message: `即將載入主題：\n「${topicTitle}」\n\n確定要建立3組演示玩家嗎？\n目前的玩家列表將被重置，版面內容將會更新。`,
          type: 'confirm',
          onConfirm: createDemoTeams
      });
  };

  const createDemoTeams = async () => {
    const demoTeamNames = ["第1組 Dakoc", "第2組 Laway", "Ohay"];
    const demoPlayers: Player[] = [
        { id: user?.uid || 'host', name: demoTeamNames[0], color: PLAYER_COLORS[0].value, position: 0, score: 0 },
        { id: 'demo-player-2', name: demoTeamNames[1], color: PLAYER_COLORS[1].value, position: 0, score: 0 },
        { id: 'demo-player-3', name: demoTeamNames[2], color: PLAYER_COLORS[2].value, position: 0, score: 0 }
    ];

    const template = TOPIC_TEMPLATES[selectedTopicId];
    const newGridData: Record<string, GridCellData> = {};
    GRID_LAYOUT_BASE.forEach(item => {
        const topicData = template.gridData[item.id] || {};
        newGridData[item.id] = {
            label: topicData.label || "...",
            color: item.defaultColor,
            textColor: item.textColor,
            image: topicData.image || '',
            sound: ''
        };
    });

    const newData = {
        players: demoPlayers, 
        currentTurnIndex: 0, 
        diceValue: 1, 
        isRolling: false,
        gridData: newGridData, 
        sentences: template.sentences, 
        dicePrompts: template.dicePrompts || [], 
        gameTitle: template.title, 
        revealedCells: {} 
    };

    try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        await setDoc(gameDocRef, newData, { merge: true });
    } catch(e) { 
        console.warn("Demo Error (Using local logic):", e);
        setGameState(prev => ({ ...prev, ...newData }));
    }
    setDialogConfig(prev => ({ ...prev, isOpen: false }));
  };

  const startCustomGame = async (customPlayers: Player[]) => {
      if (!user) return;
      if (customPlayers.length === 0) return;

      const playersWithHost = customPlayers.map((p, index) => {
        if (index === 0) return { ...p, id: user.uid };
        return { ...p, id: `manual-player-${index}` };
      });

      const template = TOPIC_TEMPLATES[selectedTopicId];
      const newGridData: Record<string, GridCellData> = {};
      GRID_LAYOUT_BASE.forEach(item => {
            const topicData = template.gridData[item.id] || {};
            newGridData[item.id] = {
                label: topicData.label || "...",
                color: item.defaultColor,
                textColor: item.textColor,
                image: topicData.image || '',
                sound: ''
            };
      });

      const newData = {
        players: playersWithHost, 
        currentTurnIndex: 0, 
        diceValue: 1, 
        isRolling: false,
        gridData: newGridData,
        sentences: template.sentences,
        dicePrompts: template.dicePrompts || [],
        gameTitle: template.title,
        revealedCells: {}
      };

      try {
          const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
          await setDoc(gameDocRef, newData, { merge: true });
      } catch(e) { 
          console.warn("Custom Game Error (Using local logic):", e); 
          setGameState(prev => ({ ...prev, ...newData }));
      }
      setShowSetupModal(false);
  };

  const updatePlayersList = async (newPlayers: Player[]) => {
      try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        await updateDoc(gameDocRef, { players: newPlayers });
      } catch(e) { 
        console.warn("Update Player Error (Using local logic):", e); 
        setGameState(prev => ({ ...prev, players: newPlayers }));
      }
  };

  const rollDice = async () => {
    if (gameState.players.length === 0 || gameState.isRolling) return;

    // Immediate Visual Feedback (Local)
    setGameState(prev => ({ ...prev, isRolling: true }));

    // Logic to calculate next state
    const performRoll = async () => {
        const roll = Math.floor(Math.random() * 6) + 1;
        try {
            const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
            // Try Cloud
            await runTransaction(db, async (transaction) => {
                const sfDoc = await transaction.get(gameDocRef);
                if (!sfDoc.exists()) throw "Document missing";
                const data = sfDoc.data() as GameState;
                const players = [...data.players];
                const currentIndex = data.currentTurnIndex;

                const currentPathIndex = players[currentIndex].position;
                let newPathIndex = (currentPathIndex + roll) % PATH_ORDER.length;
                players[currentIndex].position = newPathIndex;
                const nextIndex = (currentIndex + 1) % players.length;

                transaction.update(gameDocRef, { 
                    diceValue: roll, 
                    players: players, 
                    isRolling: false, 
                    currentTurnIndex: nextIndex, 
                    lastActionTimestamp: Date.now() 
                });
            });
        } catch(e) {
            console.warn("Roll Dice Error (Fallback to local logic):", e);
            // Fallback Local Update
            setGameState(prev => {
                const players = [...prev.players];
                const currentIndex = prev.currentTurnIndex;
                const p = { ...players[currentIndex] };
                p.position = (p.position + roll) % PATH_ORDER.length;
                players[currentIndex] = p;

                return {
                    ...prev,
                    players: players,
                    diceValue: roll,
                    isRolling: false, // Ensure rolling stops even on error
                    currentTurnIndex: (currentIndex + 1) % players.length,
                    lastActionTimestamp: Date.now()
                };
            });
        }
    };

    // Delay 1s for animation
    setTimeout(performRoll, 1000);
  };

  const updateGridCell = async (cellId: string, newData: Partial<GridCellData>) => {
    // Optimistic
    setGameState(prev => ({
        ...prev,
        gridData: { ...prev.gridData, [cellId]: { ...prev.gridData[cellId], ...newData } }
    }));
    try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        await updateDoc(gameDocRef, { [`gridData.${cellId}`]: newData });
    } catch(e) { /* Ignore offline errors */ }
    setSelectedCell(null);
  };

  const updateSentence = async (index: number, newText: string) => {
    setGameState(prev => {
        const newSentences = [...prev.sentences];
        newSentences[index] = newText;
        return { ...prev, sentences: newSentences };
    });
    try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        const newSentences = [...gameState.sentences];
        newSentences[index] = newText;
        await updateDoc(gameDocRef, { sentences: newSentences });
    } catch(e) { /* Ignore offline errors */ }
    setEditingSentenceIndex(null);
  };

  const confirmLeaveGame = () => {
    setDialogConfig({
        isOpen: true,
        title: '返回主頁',
        message: '確定要離開遊戲並返回主頁嗎？\n您的分數與位置將會移除。',
        type: 'confirm',
        onConfirm: leaveGame
    });
  };

  const leaveGame = async () => {
    if (!user) return;
    try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        const newPlayers = gameState.players.filter(p => p.id !== user.uid);
        await updateDoc(gameDocRef, { players: newPlayers });
    } catch(e) { 
        console.warn("Leave Error (Local fallback):", e);
        setGameState(prev => ({ ...prev, players: prev.players.filter(p => p.id !== user.uid) }));
    }
    setDialogConfig(prev => ({ ...prev, isOpen: false }));
  };

  const confirmResetGame = () => {
    setDialogConfig({
        isOpen: true,
        title: '重置遊戲',
        message: '確定要重置遊戲嗎？所有玩家分數和位置將歸零。\n(注意：這不會改變目前的主題設定)',
        type: 'danger',
        onConfirm: resetGame
    });
  };

  const resetGame = async () => {
     const resetPlayers = gameState.players.map(p => ({...p, position: 0, score: 0}));
     setGameState(prev => ({ ...prev, players: resetPlayers, currentTurnIndex: 0, diceValue: 1, isRolling: false, revealedCells: {} }));

     try {
       const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
       await updateDoc(gameDocRef, { players: resetPlayers, currentTurnIndex: 0, diceValue: 1, lastActionTimestamp: Date.now(), revealedCells: {} });
     } catch(e) { console.warn("Reset Error (Local fallback used):", e); }
     setDialogConfig(prev => ({ ...prev, isOpen: false }));
  };

  const confirmForceResetRoom = () => {
    setDialogConfig({
        isOpen: true,
        title: '強制重置房間',
        message: '警告：這將會清除所有現有玩家和遊戲進度！\n\n如果因為有舊玩家卡在裡面而無法切換主題，請使用此功能。',
        type: 'danger',
        onConfirm: forceResetRoom
    });
  };

  const forceResetRoom = async () => {
     setGameState(prev => ({ ...prev, players: [], currentTurnIndex: 0, diceValue: 1, isRolling: false, revealedCells: {} }));
     try {
       const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
       await updateDoc(gameDocRef, { 
           players: [], // Clear all players
           currentTurnIndex: 0, 
           diceValue: 1, 
           isRolling: false,
           lastActionTimestamp: Date.now(), 
           revealedCells: {} 
       });
     } catch(e) { console.warn("Force Reset Error (Local fallback used):", e); }
     setDialogConfig(prev => ({ ...prev, isOpen: false }));
  };

  const updateScore = async (playerIndex: number, delta: number) => {
      setGameState(prev => {
        const newPlayers = [...prev.players];
        newPlayers[playerIndex] = { ...newPlayers[playerIndex], score: (newPlayers[playerIndex].score || 0) + delta };
        return { ...prev, players: newPlayers };
      });
      try {
        const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
        const newPlayers = [...gameState.players];
        newPlayers[playerIndex].score = (newPlayers[playerIndex].score || 0) + delta;
        await updateDoc(gameDocRef, { players: newPlayers });
      } catch(e) { /* Ignore offline errors */ }
  };

  const parseLabel = (label: string) => {
      if (!label) return { amis: '', chinese: '' };
      const parts = label.split(/[\(（]/);
      const amis = parts[0].trim();
      const chinese = parts[1] ? parts[1].replace(/[\)）]$/, '').trim() : '';
      return { amis, chinese };
  };

  const gridCells = useMemo(() => {
    return GRID_LAYOUT_BASE.map(layoutItem => {
      // Fix: Cast to Partial<GridCellData> to avoid TS error on empty object property access
      const dynamicData = (gameState.gridData[layoutItem.id] || {}) as Partial<GridCellData>;
      return {
        ...layoutItem,
        label: dynamicData.label || "...",
        color: dynamicData.color || layoutItem.defaultColor,
        sound: dynamicData.sound || '',
        textColor: layoutItem.textColor || 'white',
        image: dynamicData.image || ''
      };
    });
  }, [gameState.gridData]);

  const currentPlayer = gameState.players[gameState.currentTurnIndex];
  const isJoined = gameState.players.some(p => p.id === user?.uid);

  const toggleSentence = (direction: 'prev' | 'next') => {
    const sentences = gameState.sentences || [];
    if (sentences.length === 0) return;
    if (direction === 'next') setCurrentSentenceIndex((prev) => (prev + 1) % sentences.length);
    else setCurrentSentenceIndex((prev) => (prev - 1 + sentences.length) % sentences.length);
  };

  const getSentenceStyle = (index: number) => {
      if (index === 0) return "bg-amber-500 text-white"; 
      if (index === 1) return "bg-teal-600 text-white";
      return "bg-slate-700 text-white";
  };

  const getFontSize = (text: string) => {
      if (!text) return 'text-xl';
      if (text.length > 50) return 'text-[10px] leading-tight'; 
      if (text.length > 20) return 'text-sm leading-tight';
      return 'text-lg md:text-xl';
  };

  const currentDicePrompt = gameState.dicePrompts?.[currentSentenceIndex] || "ira ko...";

  return (
    <div className="min-h-screen bg-slate-200 flex flex-col items-center justify-center p-4 font-sans text-slate-800">
      <style>{CUSTOM_CSS}</style>
      <audio ref={audioRef} hidden />
      <audio ref={stepAudioRef} src="https://res.cloudinary.com/dm1ksvptk/video/upload/v1749665342/wood_tap.mp3" hidden />
      <audio ref={bgmRef} loop src="https://res.cloudinary.com/dm1ksvptk/video/upload/qjvepdbirtbhxuhahc7l.mp3" />

      {/* Header */}
      <div className="w-full max-w-4xl mb-6 px-2">
        <div className="bg-white/80 backdrop-blur-sm rounded-xl p-4 shadow-sm flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center gap-4">
                <img src="https://res.cloudinary.com/dm1ksvptk/image/upload/v1749659604/vxem1akzssudvs0neffn.png" alt="Rolla Moggi Logo" className="w-16 h-16 rounded-full border-2 border-white shadow-md object-cover"/>
                <div>
                    <h1 className="text-xl md:text-3xl font-bold text-slate-800 tracking-wide text-center md:text-left">{gameState.gameTitle}</h1>
                    <p className="text-slate-600 font-medium flex items-center gap-2 mt-1"><Users className="w-4 h-4" /> 授課教師：蘿拉麻吉 Sonay Rolla Moggi</p>
                </div>
            </div>
            <div className="flex gap-2">
                {isJoined && (
                    <>
                    <button 
                        onClick={confirmLeaveGame}
                        className="p-3 bg-white rounded-full shadow hover:bg-red-50 text-red-600 transition-colors" 
                        title="回首頁 (離開遊戲)"
                    >
                        <Home className="w-6 h-6"/>
                    </button>
                    <button 
                        onClick={toggleRevealAll}
                        className="p-3 bg-white rounded-full shadow hover:bg-purple-50 text-purple-600 transition-colors" 
                        title="一鍵全翻/蓋牌"
                    >
                        {GRID_LAYOUT_BASE.map(c => c.id).every(id => gameState.revealedCells[id]) ? <EyeOff className="w-6 h-6"/> : <Eye className="w-6 h-6"/>}
                    </button>
                    <button 
                        onClick={() => setShowPlayerModal(true)}
                        className="p-3 bg-white rounded-full shadow hover:bg-blue-50 text-blue-600 transition-colors" 
                        title="管理學生名單"
                    >
                        <UserCog className="w-6 h-6"/>
                    </button>
                    </>
                )}
                <button onClick={playBGM} className="p-3 bg-white rounded-full shadow hover:bg-blue-50 text-blue-600 transition-colors" title="背景音樂"><Music className="w-6 h-6"/></button>
                <button onClick={() => setIsEditing(!isEditing)} className={`p-3 rounded-full shadow transition-colors ${isEditing ? 'bg-yellow-500 text-white' : 'bg-white text-slate-600 hover:bg-gray-50'}`} title="編輯模式"><Settings className="w-6 h-6" /></button>
            </div>
        </div>
      </div>

      {/* Main Game Area */}
      {isJoined ? (
        <div className="w-full flex flex-col items-center">
            {/* Status Bar */}
            <div className="w-full max-w-4xl bg-white rounded-xl shadow-sm p-4 mb-6 flex flex-wrap justify-between items-center gap-4 border-l-4 border-blue-500">
               <div className="flex items-center gap-3">
                  <div className="text-lg font-bold text-slate-700">當前回合: </div>
                  {currentPlayer && <span className="px-4 py-1.5 rounded-full text-white font-bold flex items-center gap-2 shadow-sm text-lg" style={{backgroundColor: currentPlayer.color}}>{currentPlayer.name}</span>}
               </div>
               <div className="flex gap-2 overflow-x-auto pb-2 md:pb-0 w-full md:w-auto">
                  {gameState.players.map((p, idx) => (
                      <div key={p.id} className="flex flex-col items-center p-2 bg-slate-50 rounded-lg border border-slate-100 min-w-[70px]">
                          <div className="flex items-center gap-1 mb-1">
                              <div className="w-3 h-3 rounded-full" style={{backgroundColor: p.color}}></div>
                              <span className="text-xs font-bold truncate max-w-[60px]">{p.name}</span>
                          </div>
                          <div className="flex items-center gap-1">
                              <button onClick={() => updateScore(idx, -1)} className="w-5 h-5 bg-red-100 text-red-600 rounded flex items-center justify-center hover:bg-red-200 transition-colors">-</button>
                              <span className="font-mono font-bold text-lg w-6 text-center">{p.score}</span>
                              <button onClick={() => updateScore(idx, 1)} className="w-5 h-5 bg-green-100 text-green-600 rounded flex items-center justify-center hover:bg-green-200 transition-colors">+</button>
                          </div>
                      </div>
                  ))}
               </div>
            </div>

            {/* Grid */}
            <div className="game-grid relative">
               {gridCells.map(cell => {
                 const playersHere = displayPlayers.filter(p => PATH_ORDER[p.position] === cell.id);
                 const isRevealed = gameState.revealedCells[cell.id] || false;
                 const hasImage = !!cell.image;
                 const { amis, chinese } = parseLabel(cell.label); 

                 return (
                   <div key={cell.id} className="grid-cell wood-texture" style={{ gridArea: cell.area, backgroundColor: cell.color }} onClick={() => {
                        if(isEditing) { setSelectedCell(cell); } else {
                            playSound(cell.sound);
                            toggleCellReveal(cell.id);
                            const el = document.getElementById(`cell-${cell.id}`);
                            if(el) { el.classList.add('active'); setTimeout(() => el.classList.remove('active'), 300); }
                        }
                     }} id={`cell-${cell.id}`}>
                     {isEditing && <div className="absolute top-1 right-1 bg-white/80 p-1 rounded-full shadow-sm z-20"><Edit3 className="w-3 h-3 text-gray-600"/></div>}
                     <div className="flex flex-col items-center justify-center w-full h-full pt-1 pointer-events-none z-0 relative">
                         {!isRevealed && <span className={`font-bold drop-shadow-md text-center px-1 break-words w-full ${getFontSize(amis)}`} style={{ color: cell.textColor }}>{amis}</span>}

                         {isRevealed && (
                             hasImage ? 
                                <img src={cell.image} alt="" className="absolute inset-0 w-full h-full object-cover rounded-lg z-10" /> 
                                : 
                                <span className={`font-bold drop-shadow-md text-center px-1 break-words w-full ${getFontSize(chinese || amis)}`} style={{ color: cell.textColor }}>{chinese || amis}</span>
                         )}
                     </div>
                     <div className="token-container z-20">
                        {playersHere.map(p => <div key={p.id} className="player-token" style={{backgroundColor: p.color}} title={p.name}></div>)}
                     </div>
                   </div>
                 );
               })}

               {/* Center Control */}
               <div className="grid-center">
                  <div className={`w-full max-w-xs rounded-xl p-4 mb-4 shadow-lg text-center relative group transition-colors duration-300 ${getSentenceStyle(currentSentenceIndex)}`} onClick={() => { if(isEditing) setEditingSentenceIndex(currentSentenceIndex); }}>
                      {isEditing && <div className="absolute top-1 right-1 bg-white/30 p-1 rounded-full cursor-pointer hover:bg-white/50"><Edit3 className="w-4 h-4 text-white"/></div>}
                      <div className="text-white/80 text-sm mb-2 font-bold uppercase tracking-wider border-b border-white/20 pb-1">句型練習 ({gameState.sentences.length > 0 ? currentSentenceIndex + 1 : 0}/{gameState.sentences.length})</div>
                      <div className="flex items-center justify-between">
                          <button onClick={(e) => { e.stopPropagation(); toggleSentence('prev'); }} className="text-white/50 hover:text-white transition-colors p-1"><ChevronLeft className="w-8 h-8" /></button>
                          <div className="text-white font-bold text-xl md:text-2xl px-2 min-h-[4rem] flex items-center justify-center drop-shadow-md leading-tight">{gameState.sentences[currentSentenceIndex]}</div>
                          <button onClick={(e) => { e.stopPropagation(); toggleSentence('next'); }} className="text-white/50 hover:text-white transition-colors p-1"><ChevronRight className="w-8 h-8" /></button>
                      </div>

                      <div className="grid grid-cols-2 gap-2 mt-3 pt-2 border-t border-white/20 w-full">
                          <select className="bg-teal-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-teal-500 transition-colors appearance-none text-center font-bold" value={selectedNumber} onChange={(e) => setSelectedNumber(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">數字</option>
                               {NUMBER_SET.map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                          <select className="bg-rose-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-rose-500 transition-colors appearance-none text-center font-bold" value={selectedGenitive} onChange={(e) => setSelectedGenitive(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">屬格代名詞</option>
                               {GENITIVE_PRONOUNS.map(p => <option key={p} value={p}>{p}</option>)}
                          </select>
                          <select className="bg-indigo-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-indigo-500 transition-colors appearance-none text-center font-bold" value={selectedNominative} onChange={(e) => setSelectedNominative(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">主格代名詞</option>
                               {NOMINATIVE_PRONOUNS.map(p => <option key={p} value={p}>{p}</option>)}
                          </select>
                          <select className="bg-amber-600 text-white text-sm rounded px-2 py-1 outline-none w-full cursor-pointer hover:bg-amber-500 transition-colors appearance-none text-center font-bold" value={selectedPeopleCount} onChange={(e) => setSelectedPeopleCount(e.target.value)} onClick={(e) => e.stopPropagation()}>
                               <option value="">人數</option>
                               {PEOPLE_COUNT_SET.map(p => <option key={p} value={p}>{p}</option>)}
                          </select>
                      </div>
                  </div>
                  <div className="mb-4 relative w-20 h-20 md:w-24 md:h-24 flex items-center justify-center cursor-pointer" onClick={rollDice}>
                      <div className="absolute -top-3 -right-12 bg-yellow-400 text-amber-900 px-3 py-1 rounded-sm font-bold shadow-md transform rotate-12 z-20 border-2 border-white text-sm whitespace-nowrap animate-bounce" style={{animationDuration: '2s'}}>{currentDicePrompt}</div>
                      <div className={`dice-3d w-full h-full bg-orange-100 rounded-xl border-4 border-amber-800 flex items-center justify-center shadow-lg ${gameState.isRolling ? 'rolling' : ''}`}>
                          <div className="grid grid-cols-3 grid-rows-3 gap-1 p-3 w-full h-full">
                              {[...Array(9)].map((_, i) => {
                                  const val = gameState.diceValue;
                                  let show = false;
                                  if (i === 4 && (val === 1 || val === 3 || val === 5)) show = true;
                                  if ((i === 0 || i === 8) && (val > 1)) show = true;
                                  if ((i === 2 || i === 6) && (val > 3)) show = true;
                                  if ((i === 3 || i === 5) && (val === 6)) show = true;
                                  return <div key={i} className="flex items-center justify-center">{show && <div className="w-3 h-3 md:w-4 md:h-4 bg-amber-900 rounded-full"></div>}</div>;
                              })}
                          </div>
                      </div>
                  </div>
                  <button onClick={rollDice} disabled={gameState.isRolling} className={`px-6 py-2 rounded-full text-base font-bold shadow-lg transform transition-all whitespace-nowrap ${gameState.isRolling ? 'bg-gray-500 cursor-not-allowed scale-95' : 'bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 text-white hover:scale-105 active:scale-95'}`}>{gameState.isRolling ? '...' : '擲骰子'}</button>
                  <div className="mt-6 flex gap-4"><button onClick={confirmResetGame} className="text-gray-400 hover:text-white flex items-center gap-1 text-sm bg-black/20 px-3 py-1 rounded-full transition-colors"><RotateCcw className="w-3 h-3"/> 重置遊戲</button></div>
               </div>
            </div>
        </div>
      ) : (
        /* Login Screen */
        <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md text-center border-t-8 border-amber-500 relative animate-in fade-in zoom-in duration-300">
             <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-slate-100 overflow-hidden"><img src="https://res.cloudinary.com/dm1ksvptk/image/upload/v1749659604/vxem1akzssudvs0neffn.png" alt="Logo" className="w-full h-full object-cover"/></div>
             <h2 className="text-2xl font-bold text-gray-800 mb-1">歡迎來到族語大富翁</h2>
             <p className="text-gray-500 mb-4 font-medium">{TOPIC_TEMPLATES[selectedTopicId]?.title || gameState.gameTitle || "馬蘭阿美語"}</p>

             <div className="mb-6 flex flex-col items-center justify-center bg-gray-50 p-4 rounded-xl border border-dashed border-gray-300"><img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=https://example.com/game`} alt="Scan to join" className="w-32 h-32 mb-2 opacity-80"/><span className="text-xs text-gray-500 flex items-center gap-1"><QrCode className="w-3 h-3"/> 掃描加入遊戲 (學生用)</span></div>
             <div className="border-t border-gray-200 my-4 pt-4">
                <p className="text-sm font-bold text-gray-600 mb-3 flex items-center justify-center gap-1"><Settings className="w-4 h-4"/> 教師設定區</p>

                <div className="mb-3 text-left">
                    <label className="text-xs font-bold text-gray-500 mb-1 block pl-1">選擇課程主題 (自動更新標題與單字)</label>
                    <div className="relative">
                        <select 
                            value={selectedTopicId} 
                            onChange={(e) => setSelectedTopicId(e.target.value)}
                            className="w-full p-2 pl-9 bg-slate-50 border border-slate-200 rounded-lg text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500"
                        >
                            <option value="topic1">1. 生活會話篇 第11課 (兄弟姊妹)</option>
                            <option value="topic2">2. 第5階-9課 riyal 海</option>
                            <option value="topic3">3. 情境族語 第 10課 適品買賣</option>
                            <option value="topic4">4. 族語期末檢測</option>
                        </select>
                        <BookOpen className="w-4 h-4 text-gray-400 absolute left-3 top-2.5 pointer-events-none"/>
                    </div>
                </div>

                <div className="flex gap-2 mb-4">
                    <button onClick={confirmDemoTeams} className="flex-1 bg-indigo-600 text-white font-bold py-3 rounded-xl shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"><Zap className="fill-current w-5 h-5" /> 演示模式</button>
                    <button onClick={() => setShowSetupModal(true)} className="flex-1 bg-teal-600 text-white font-bold py-3 rounded-xl shadow-lg hover:bg-teal-700 transition-all flex items-center justify-center gap-2"><PenTool className="fill-current w-5 h-5" /> 手動名單</button>
                </div>
             </div>
             <div className="relative flex py-2 items-center"><div className="flex-grow border-t border-gray-300"></div><span className="flex-shrink-0 mx-4 text-gray-400 text-xs">或單獨加入 (最多7組)</span><div className="flex-grow border-t border-gray-300"></div></div>
             <div className="mb-4 mt-2"><input type="text" placeholder="輸入隊伍名稱" className="w-full text-center text-lg border-2 border-gray-200 rounded-xl p-3 focus:border-amber-500 outline-none" value={localPlayerName} onChange={e => setLocalPlayerName(e.target.value)} onKeyDown={e => e.key === 'Enter' && joinGame()}/></div>
             <div className="flex flex-col gap-2">
                <button onClick={joinGame} disabled={!localPlayerName.trim()} className="w-full bg-amber-500 text-white text-xl font-bold py-3 rounded-xl shadow-lg hover:bg-amber-600 disabled:opacity-50 transition-all flex items-center justify-center gap-2"><Play className="fill-current w-5 h-5" /> 開始遊戲</button>
                {gameState.players.length > 0 && (
                    <button onClick={confirmForceResetRoom} className="w-full bg-red-100 text-red-600 text-sm font-bold py-2 rounded-xl hover:bg-red-200 transition-all flex items-center justify-center gap-2">
                        <RotateCcw className="w-4 h-4" /> 強制重置房間 (清除卡住的舊遊戲)
                    </button>
                )}
             </div>
             <p className="mt-4 text-xs text-gray-400">目前已有 {gameState.players.length} 組玩家加入</p>
        </div>
      )}

      {/* Modals */}
      {isEditing && selectedCell && <EditModal selectedCell={selectedCell} onClose={() => setSelectedCell(null)} onSave={updateGridCell} />}
      {isEditing && editingSentenceIndex !== null && gameState.sentences && <SentenceEditModal index={editingSentenceIndex} sentence={gameState.sentences[editingSentenceIndex]} onClose={() => setEditingSentenceIndex(null)} onSave={updateSentence} />}
      {showPlayerModal && <PlayerListModal players={gameState.players} onClose={() => setShowPlayerModal(false)} onUpdatePlayers={updatePlayersList} />}
      {showSetupModal && <PlayerListModal players={[]} onClose={() => setShowSetupModal(false)} onUpdatePlayers={startCustomGame} title="手動建立名單 (教師用)" confirmLabel="建立並開始遊戲" />}

      {/* Global Dialog */}
      <Dialog 
        isOpen={dialogConfig.isOpen}
        title={dialogConfig.title}
        message={dialogConfig.message}
        type={dialogConfig.type}
        data={dialogConfig.data}
        onConfirm={dialogConfig.onConfirm}
        onCancel={() => setDialogConfig(prev => ({...prev, isOpen: false}))}
      />
    </div>
  );
}

