`;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { initializeApp } from 'firebase/app';
import { getAuth, signInAnonymously, onAuthStateChanged, signInWithCustomToken, User as FirebaseUser } from 'firebase/auth';
import { getFirestore, doc, onSnapshot, setDoc, updateDoc, arrayUnion, runTransaction } from 'firebase/firestore';
import { Settings, Play, Edit3, RotateCcw, Users, Music, ChevronLeft, ChevronRight, QrCode, Zap, Image as ImageIcon, Eye, EyeOff, PenTool, BookOpen, Home, UserCog } from 'lucide-react';
import { TOPIC_TEMPLATES, GRID_LAYOUT_BASE, PATH_ORDER, PLAYER_COLORS, NUMBER_SET, NOMINATIVE_PRONOUNS, GENITIVE_PRONOUNS, PEOPLE_COUNT_SET, ROOM_ID, DEFAULT_APP_ID, CUSTOM_CSS } from './constants';
import { Dialog, EditModal, SentenceEditModal, PlayerListModal } from './components/GameModals';
import { GameState, DialogConfig, GridCellData, Player } from './types';

// --- Firebase Configuration ---
