                     <div className="flex flex-col items-center justify-center w-full h-full pt-0.5 pointer-events-none z-0 relative">
                         {!isRevealed && <span className={`font-bold drop-shadow-md text-center px-0.5 break-words w-full ${fontSizeClass}`} style={{ color: cell.textColor }}>{amis}</span>}

