                             hasImage ? 
                                <img src={cell.image} alt="" className="absolute inset-0 w-full h-full object-cover rounded-md md:rounded-lg z-10" /> 
                                : 
                                <span className={`font-bold drop-shadow-md text-center px-0.5 break-words w-full ${fontSizeClass}`} style={{ color: cell.textColor }}>{chinese || amis}</span>
                         )}
                     </div>
