                      </div>

                      <div className="flex items-center justify-between">
                          <button onClick={(e) => { e.stopPropagation(); toggleSentence('prev'); }} className="text-white/50 hover:text-white transition-colors p-0.5"><ChevronLeft className="w-5 h-5 md:w-8 md:h-8" /></button>
                          <div className="text-white font-bold text-sm md:text-2xl px-1 min-h-[3rem] md:min-h-[4rem] flex items-center justify-center drop-shadow-md leading-tight text-center">
                              {gameState.sentences[currentSentenceIndex]}
                          </div>
                          <button onClick={(e) => { e.stopPropagation(); toggleSentence('next'); }} className="text-white/50 hover:text-white transition-colors p-0.5"><ChevronRight className="w-5 h-5 md:w-8 md:h-8" /></button>
                      </div>

                      {/* Dropdowns: 2x2 on Mobile */}
                      <div className="grid grid-cols-2 gap-1 md:gap-2 mt-2 pt-1 border-t border-white/20 w-full">
                          {[
                              { val: selectedNumber, set: setSelectedNumber, list: NUMBER_SET, label: "數字", bg: "bg-teal-600" },
                              { val: selectedGenitive, set: setSelectedGenitive, list: GENITIVE_PRONOUNS, label: "屬格", bg: "bg-rose-600" },
                              { val: selectedNominative, set: setSelectedNominative, list: NOMINATIVE_PRONOUNS, label: "主格", bg: "bg-indigo-600" },
                              { val: selectedPeopleCount, set: setSelectedPeopleCount, list: PEOPLE_COUNT_SET, label: "人數", bg: "bg-amber-600" }
                          ].map((item, i) => (
                              <select 
                                  key={i}
                                  className={`${item.bg} text-white text-[10px] md:text-sm rounded px-1 py-1 outline-none w-full cursor-pointer hover:opacity-90 transition-opacity appearance-none text-center font-bold`} 
                                  value={item.val} 
                                  onChange={(e) => item.set(e.target.value)} 
                                  onClick={(e) => e.stopPropagation()}
                              >
                               <option value="">{item.label}</option>
                               {item.list.map(n => <option key={n} value={n}>{n}</option>)}
                          </select>
                          ))}
                      </div>
                  </div>

                  {/* Dice Area */}
                  <div className="flex flex-col items-center justify-center gap-1 md:gap-4 flex-1">
                      <div className="relative flex items-center justify-center cursor-pointer" onClick={rollDice}>
                          <div className="absolute -top-6 -right-8 md:-top-3 md:-right-12 bg-yellow-400 text-amber-900 px-2 py-0.5 md:px-3 md:py-1 rounded-sm font-bold shadow-md transform rotate-12 z-20 border border-white text-[10px] md:text-sm whitespace-nowrap animate-bounce" style={{animationDuration: '2s'}}>
                              {currentDicePrompt}
                          </div>
                          <div className={`dice-3d bg-orange-100 rounded-lg md:rounded-xl border-2 md:border-4 border-amber-800 flex items-center justify-center shadow-lg ${gameState.isRolling ? 'rolling' : ''}`}>
                              <div className="grid grid-cols-3 grid-rows-3 gap-0.5 md:gap-1 p-1 md:p-3 w-full h-full">
                                  {[...Array(9)].map((_, i) => {
                                      const val = gameState.diceValue;
                                      let show = false;
                                      if (i === 4 && (val === 1 || val === 3 || val === 5)) show = true;
                                      if ((i === 0 || i === 8) && (val > 1)) show = true;
                                      if ((i === 2 || i === 6) && (val > 3)) show = true;
                                      if ((i === 3 || i === 5) && (val === 6)) show = true;
                                      return <div key={i} className="flex items-center justify-center">{show && <div className="w-2 h-2 md:w-4 md:h-4 bg-amber-900 rounded-full"></div>}</div>;
                                  })}
                              </div>
                          </div>
                      </div>

                      <button onClick={rollDice} disabled={gameState.isRolling} className={`px-4 py-1.5 md:px-6 md:py-2 rounded-full text-xs md:text-base font-bold shadow-lg transform transition-all whitespace-nowrap mt-1 md:mt-0 ${gameState.isRolling ? 'bg-gray-500 cursor-not-allowed scale-95' : 'bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 text-white hover:scale-105 active:scale-95'}`}>
                          {gameState.isRolling ? '...' : '擲骰子'}
                      </button>

                      <button onClick={confirmResetGame} className="text-gray-400 hover:text-white flex items-center gap-1 text-[10px] md:text-sm bg-black/20 px-2 py-1 rounded-full transition-colors mt-1 md:mt-2">
                          <RotateCcw className="w-3 h-3"/> 重置
                      </button>
                  </div>
               </div>
            </div>
        </div>
      ) : (
        /* Login Screen */
        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-xl w-full max-w-sm md:max-w-md text-center border-t-8 border-amber-500 relative animate-in fade-in zoom-in duration-300 mx-4">
