```
function MonopolyGame() {
    const [gameState, setGameState] = useState<GameState>(initialGameState);
    const [displayPlayers, setDisplayPlayers] = useState<DisplayPlayer[]>([]);

    useEffect(() => {
        setDisplayPlayers(prev => {
        //   if (prev.length === gameState.players.length) {
        //     const allIdsMatch = prev.every((p, i) => p.id === gameState.players[i].id);
        //     if (allIdsMatch) return prev; 
        //   }
          return gameState.players.map(targetP => {
            const existing = prev.find(p => p.id === targetP.id);
            if (existing) return existing ? { ...existing, position: targetP.position } : targetP as DisplayPlayer; 
            return targetP as DisplayPlayer; 
          });
        });
    }, [gameState.players]);

    useEffect(() => {
        if (gameState.players.length === 0) return;
        const moveInterval = setInterval(() => {
            setDisplayPlayers(prev => {
                const nextPlayers = [...prev];
                let updated = false;
                gameState.players.forEach((targetPlayer) => {
                    const index = nextPlayers.findIndex(p => p.id === targetPlayer.id);
                    if (index === -1) return; 

                    const currentPos = nextPlayers[index].position;
                    const targetPos = targetPlayer.position;

                    if (currentPos !== targetPos) {
                        let nextPosition = currentPos;
                        if (currentPos < targetPos) {
                            nextPosition = Math.min(currentPos + 1, targetPos);
                        } else {
                            nextPosition = Math.max(currentPos - 1, targetPos);
                        }

                        nextPlayers[index] = { ...nextPlayers[index], position: nextPosition };
                        updated = true;
                    }
                });
                if (updated) {
                    return nextPlayers;
                } else {
                    return prev;
                }
            });
        }, 100);

        return () => clearInterval(moveInterval);
    }, [gameState.players]);

  return (
    <>
      <GameTable
        gameState={gameState}
        displayPlayers={displayPlayers}
      />
    </>
  );
}
```


