                      </div>
                  ))}
               </div>
            </div>

            {/* Grid */}
            <div className="game-grid relative">
               {gridCells.map(cell => {
                 const playersHere = displayPlayers.filter(p => PATH_ORDER[p.position] === cell.id);
                 const isRevealed = gameState.revealedCells[cell.id] || false;
                 const hasImage = !!cell.image;
                 const { amis, chinese } = parseLabel(cell.label); 
                 const fontSizeClass = getFontSize(isRevealed ? (chinese || amis) : amis);

                 return (
                   <div key={cell.id} className="grid-cell wood-texture" style={{ gridArea: cell.area, backgroundColor: cell.color }} onClick={() => {
                        if(isEditing) { setSelectedCell(cell); } else {
                            playSound(cell.sound);
                            toggleCellReveal(cell.id);
                            const el = document.getElementById(`cell-${cell.id}`);
                            if(el) { el.classList.add('active'); setTimeout(() => el.classList.remove('active'), 300); }
                        }
                     }} id={`cell-${cell.id}`}>
                     {isEditing && <div className="absolute top-1 right-1 bg-white/80 p-0.5 rounded-full shadow-sm z-20"><Edit3 className="w-2 h-2 md:w-3 md:h-3 text-gray-600"/></div>}
                     <div className="flex flex-col items-center justify-center w-full h-full pt-0.5 pointer-events-none z-0 relative">
                         {!isRevealed && <span className={`font-bold drop-shadow-md text-center px-0.5 break-words w-full ${fontSizeClass}`} style={{ color: cell.textColor }}>{amis}</span>}

                         {isRevealed && (
                             hasImage ? 
                                <img src={cell.image} alt="" className="absolute inset-0 w-full h-full object-cover rounded-md md:rounded-lg z-10" /> 
                                : 
                                <span className={`font-bold drop-shadow-md text-center px-0.5 break-words w-full ${fontSizeClass}`} style={{ color: cell.textColor }}>{chinese || amis}</span>
                         )}
                     </div>
                     <div className="token-container z-20">
                        {playersHere.map(p => <div key={p.id} className="player-token" style={{backgroundColor: p.color}} title={p.name}></div>)}
                     </div>
                   </div>
                 );
               })}

               {/* Center Control - Compact for Mobile */}
               <div className="grid-center">
                  <div className={`w-full max-w-xs rounded-lg md:rounded-xl p-2 md:p-4 mb-1 md:mb-4 shadow-lg text-center relative group transition-colors duration-300 ${getSentenceStyle(currentSentenceIndex)}`} onClick={() => { if(isEditing) setEditingSentenceIndex(currentSentenceIndex); }}>
                      {isEditing && <div className="absolute top-1 right-1 bg-white/30 p-1 rounded-full cursor-pointer hover:bg-white/50"><Edit3 className="w-3 h-3 md:w-4 md:h-4 text-white"/></div>}
                      <div className="text-white/80 text-[10px] md:text-sm mb-1 md:mb-2 font-bold uppercase tracking-wider border-b border-white/20 pb-0.5 md:pb-1">
