                              <div className="grid grid-cols-3 grid-rows-3 gap-0.5 md:gap-1 p-1 md:p-3 w-full h-full">
                                  {[...Array(9)].map((_, i) => {
                                      const val = gameState.diceValue;
                                      let show = false;
                                      if (i === 4 && (val === 1 || val === 3 || val === 5)) show = true;
                                      if ((i === 0 || i === 8) && (val > 1)) show = true;
