       const gameDocRef = doc(db, 'artifacts', appId, 'public', 'data', 'monopoly_games', ROOM_ID);
       await updateDoc(gameDocRef, { players: resetPlayers, currentTurnIndex: 0, diceValue: 1, lastActionTimestamp: Date.now(), revealedCells: {} });
