                        {GRID_LAYOUT_BASE.map(c => c.id).every(id => gameState.revealedCells[id]) ? <EyeOff className="w-5 h-5 md:w-6 md:h-6"/> : <Eye className="w-5 h-5 md:w-6 md:h-6"/>}
                    </button>
                    <button 
