                              {currentDicePrompt}
                          </div>
                          <div className={`dice-3d bg-orange-100 rounded-lg md:rounded-xl border-2 md:border-4 border-amber-800 flex items-center justify-center shadow-lg ${gameState.isRolling ? 'rolling' : ''}`}>
                              <div className="grid grid-cols-3 grid-rows-3 gap-0.5 md:gap-1 p-1 md:p-3 w-full h-full">
                                  {[...Array(9)].map((_, i) => {
                                      const val = gameState.diceValue;
                                      let show = false;
                                      if (i === 4 && (val === 1 || val === 3 || val === 5)) show = true;
                                      if ((i === 0 || i === 8) && (val > 1)) show = true;
                                      if ((i === 2 || i === 6) && (val > 3)) show = true;
                                      if ((i === 3 || i === 5) && (val === 6)) show = true;
                                      return <div key={i} className="flex items-center justify-center">{show && <div className="w-2 h-2 md:w-4 md:h-4 bg-amber-900 rounded-full"></div>}</div>;
                                  })}
                              </div>
                          </div>
                      </div>

                      <button onClick={rollDice} disabled={gameState.isRolling} className={`px-4 py-1.5 md:px-6 md:py-2 rounded-full text-xs md:text-base font-bold shadow-lg transform transition-all whitespace-nowrap mt-1 md:mt-0 ${gameState.isRolling ? 'bg-gray-500 cursor-not-allowed scale-95' : 'bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 text-white hover:scale-105 active:scale-95'}`}>
                          {gameState.isRolling ? '...' : '擲骰子'}
                      </button>

                      <button onClick={confirmResetGame} className="text-gray-400 hover:text-white flex items-center gap-1 text-[10px] md:text-sm bg-black/20 px-2 py-1 rounded-full transition-colors mt-1 md:mt-2">
