      <div className="bg-white rounded-2xl p-6 w-full max-w-md shadow-2xl">
        <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
           <Edit3 className="w-5 h-5 text-blue-600"/> 編輯句型 {index + 1}
        </h3>
        <textarea value={text} onChange={e => setText(e.target.value)} className="w-full border rounded-lg p-3 h-32 text-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none"/>
        <div className="mt-6 flex justify-end gap-3">
          <button onClick={onClose} className="px-4 py-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">取消</button>
