                                  {[...Array(9)].map((_, i) => {
                                      const val = gameState.diceValue;
                                      let show = false;
                                      if (i === 4 && (val === 1 || val === 3 || val === 5)) show = true;
                                      if ((i === 0 || i === 8) && (val > 1)) show = true;
                                      if ((i === 2 || i === 6) && (val > 3)) show = true;
                                      if ((i === 3 || i === 5) && (val === 6)) show = true;
                                      return <div key={i} className="flex items-center justify-center">{show && <div className="w-2 h-2 md:w-4 md:h-4 bg-amber-900 rounded-full"></div>}</div>;
                                  })}
                              </div>
                          </div>
                      </div>

                      <button onClick={rollDice} disabled={gameState.isRolling} className={`px-4 py-1.5 md:px-6 md:py-2 rounded-full text-xs md:text-base font-bold shadow-lg transform transition-all whitespace-nowrap mt-1 md:mt-0 ${gameState.isRolling ? 'bg-gray-500 cursor-not-allowed scale-95' : 'bg-gradient-to-r from-amber-500 to-orange-600 hover:from-amber-400 hover:to-orange-500 text-white hover:scale-105 active:scale-95'}`}>
                          {gameState.isRolling ? '...' : '擲骰子'}
                      </button>

                      <button onClick={confirmResetGame} className="text-gray-400 hover:text-white flex items-center gap-1 text-[10px] md:text-sm bg-black/20 px-2 py-1 rounded-full transition-colors mt-1 md:mt-2">
                          <RotateCcw className="w-3 h-3"/> 重置
                      </button>
                  </div>
               </div>
            </div>
        </div>
      ) : (
        /* Login Screen */
        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-xl w-full max-w-sm md:max-w-md text-center border-t-8 border-amber-500 relative animate-in fade-in zoom-in duration-300 mx-4">
             <div className="w-16 h-16 md:w-24 md:h-24 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-slate-100 overflow-hidden"><img src={SITE_CONFIG.logoUrl} alt="Logo" className="w-full h-full object-cover"/></div>
             <h2 className="text-xl md:text-2xl font-bold text-gray-800 mb-1">{SITE_CONFIG.websiteTitle}</h2>
             <p className="text-gray-500 mb-4 font-medium text-sm md:text-base">{allTopics[selectedTopicId]?.title || gameState.gameTitle || SITE_CONFIG.defaultTopicName}</p>

             <div className="mb-6 flex flex-col items-center justify-center bg-gray-50 p-4 rounded-xl border border-dashed border-gray-300"><img src="https://res.cloudinary.com/dm1ksvptk/image/upload/v1769527950/qr_cord_%E5%A4%A7%E5%AF%8C%E7%BF%81-removebg-preview_1_iiu01u.png" alt="Scan to join" className="w-full max-w-[250px] h-auto object-contain mb-2"/><span className="text-xs text-gray-500 flex items-center gap-1"><QrCode className="w-3 h-3"/> 掃描加入遊戲 (學生用)</span></div>
             <div className="border-t border-gray-200 my-4 pt-4">
                <p className="text-sm font-bold text-gray-600 mb-3 flex items-center justify-center gap-1"><Settings className="w-4 h-4"/> 教師設定區</p>

                <div className="mb-3 text-left">
                    <label className="text-xs font-bold text-gray-500 mb-1 block pl-1">授課教師 (點擊修改)</label>
                    <div 
                        className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm text-gray-700 flex items-center justify-between cursor-pointer hover:border-blue-400 hover:text-blue-600 transition-colors"
                        onClick={updateInstructorName}
                    >
                        {instructorName}
                        <Pencil className="w-4 h-4 text-gray-400"/>
                    </div>
                </div>

                <div className="mb-3 text-left">
                    <label className="text-xs font-bold text-gray-500 mb-1 block pl-1">選擇課程主題</label>
                    <div className="relative flex items-center gap-2">
                        <div className="relative flex-1">
                            <select 
                                value={selectedTopicId} 
                                onChange={(e) => setSelectedTopicId(e.target.value)}
                                className="w-full p-2 pl-9 bg-slate-50 border border-slate-200 rounded-lg text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500 truncate pr-8"
                            >
                                {Object.entries(allTopics).map(([id, topic], index) => (
                                    <option key={id} value={id}>
                                        {index + 1}. {(topic as TopicTemplate).title}
                                    </option>
                                ))}
                            </select>
                            <BookOpen className="w-4 h-4 text-gray-400 absolute left-3 top-2.5 pointer-events-none"/>
                        </div>
                        {selectedTopicId.startsWith('custom-') && (
                            <button 
                                onClick={(e) => deleteCustomTopic(e, selectedTopicId)}
                                className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                                title="刪除此自訂主題"
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        )}
                    </div>
                </div>

                <div className="flex gap-2 mb-4">
                    <button onClick={confirmDemoTeams} className="flex-1 bg-indigo-600 text-white font-bold py-2 md:py-3 rounded-xl shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2 text-sm"><Zap className="fill-current w-4 h-4 md:w-5 md:h-5" /> 演示模式</button>
                    <button onClick={() => setShowSetupModal(true)} className="flex-1 bg-teal-600 text-white font-bold py-2 md:py-3 rounded-xl shadow-lg hover:bg-teal-700 transition-all flex items-center justify-center gap-2 text-sm"><PenTool className="fill-current w-4 h-4 md:w-5 md:h-5" /> 手動名單</button>
                </div>
                <button onClick={() => setShowSheetModal(true)} className="w-full bg-green-50 text-green-700 font-bold py-2 md:py-3 rounded-xl shadow-sm border border-green-200 hover:bg-green-100 transition-all flex items-center justify-center gap-2 text-sm mb-4">
                    <FileSpreadsheet className="w-4 h-4 md:w-5 md:h-5"/> 匯入 Google Sheets 題庫
                </button>
             </div>
             <div className="relative flex py-2 items-center"><div className="flex-grow border-t border-gray-300"></div><span className="flex-shrink-0 mx-4 text-gray-400 text-xs">或單獨加入</span><div className="flex-grow border-t border-gray-300"></div></div>
             <div className="mb-4 mt-2"><input type="text" placeholder="輸入隊伍名稱" className="w-full text-center text-lg border-2 border-gray-200 rounded-xl p-3 focus:border-amber-500 outline-none" value={localPlayerName} onChange={e => setLocalPlayerName(e.target.value)} onKeyDown={e => e.key === 'Enter' && joinGame()}/></div>
             <div className="flex flex-col gap-2">
                <button onClick={joinGame} disabled={!localPlayerName.trim()} className="w-full bg-amber-500 text-white text-xl font-bold py-3 rounded-xl shadow-lg hover:bg-amber-600 disabled:opacity-50 transition-all flex items-center justify-center gap-2"><Play className="fill-current w-5 h-5" /> 開始遊戲</button>
                {gameState.players.length > 0 && (
                    <button onClick={confirmForceResetRoom} className="w-full bg-red-100 text-red-600 text-sm font-bold py-2 rounded-xl hover:bg-red-200 transition-all flex items-center justify-center gap-2">
                        <RotateCcw className="w-4 h-4" /> 強制重置房間
                    </button>
                )}
             </div>
             <p className="mt-4 text-xs text-gray-400">目前已有 {gameState.players.length} 組玩家加入</p>
        </div>
      )}

      {/* Modals */}
      {isEditing && selectedCell && <EditModal selectedCell={selectedCell} onClose={() => setSelectedCell(null)} onSave={updateGridCell} onAiGenerate={handleGenerateAIImage} />}
      {isEditing && editingSentenceIndex !== null && gameState.sentences && <SentenceEditModal index={editingSentenceIndex} sentence={gameState.sentences[editingSentenceIndex]} onClose={() => setEditingSentenceIndex(null)} onSave={updateSentence} />}
      {showPlayerModal && <PlayerListModal players={gameState.players} onClose={() => setShowPlayerModal(false)} onUpdatePlayers={updatePlayersList} />}
      {showSetupModal && <PlayerListModal players={[]} onClose={() => setShowSetupModal(false)} onUpdatePlayers={startCustomGame} title="手動建立名單 (教師用)" confirmLabel="建立並開始遊戲" />}
      {showSheetModal && <SheetImportModal onClose={() => setShowSheetModal(false)} onImport={handleSheetImport} />}

      {/* Global Dialog */}
      <Dialog 
        isOpen={dialogConfig.isOpen}
        title={dialogConfig.title}
        message={dialogConfig.message}
        type={dialogConfig.type}
        data={dialogConfig.data}
        onConfirm={dialogConfig.onConfirm || (() => setDialogConfig(prev => ({...prev, isOpen: false})))}
        onCancel={() => setDialogConfig(prev => ({...prev, isOpen: false}))}
      />
    </div>
  );
}

import React, { useState } from 'react';
import { Edit3, X, Save, ImageIcon, UserCog, Trash2, Users, Plus, FileSpreadsheet, ExternalLink, Download, Wand2, Loader2, Type } from 'lucide-react';
import { DialogConfig, GridCellData, Player } from '../types';
import { PLAYER_COLORS } from '../constants';

export const Dialog: React.FC<DialogConfig> = ({ isOpen, title, message, onConfirm, onCancel, type = 'confirm' }) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[60] p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl p-6 w-full max-w-sm shadow-2xl scale-100 transform transition-all">
        <h3 className={`text-xl font-bold mb-2 ${type === 'danger' ? 'text-red-600' : 'text-slate-800'}`}>
            {title}
        </h3>
        <p className="text-slate-600 mb-6 leading-relaxed whitespace-pre-line">{message}</p>
        <div className="flex justify-end gap-3">
            {type !== 'alert' && onCancel && (
                <button 
                    onClick={onCancel} 
                    className="px-4 py-2 text-slate-600 hover:bg-slate-100 rounded-lg font-medium transition-colors"
                >
                    取消
                </button>
            )}
            <button
                onClick={onConfirm}
                className={`px-4 py-2 rounded-lg text-white font-medium shadow-md transition-colors ${
                    type === 'danger' ? 'bg-red-500 hover:bg-red-600' : 'bg-blue-600 hover:bg-blue-700'
                }`}
            >
                {type === 'alert' ? '知道了' : '確定'}
            </button>
        </div>
      </div>
    </div>
  );
};

interface EditModalProps {
    selectedCell: { id: string } & GridCellData;
    onClose: () => void;
    onSave: (id: string, data: Partial<GridCellData>) => void;
    onAiGenerate?: (label: string) => Promise<string | null>;
}

export const EditModal: React.FC<EditModalProps> = ({ selectedCell, onClose, onSave, onAiGenerate }) => {
  // Parsing helper to handle legacy label format "Amis (Chinese)"
  const parseInitial = (data: GridCellData) => {
      if (data.amis || data.chinese) return { amis: data.amis || '', chinese: data.chinese || '' };
      const parts = (data.label || '').split(/[\(（]/);
      return { 
          amis: parts[0]?.trim() || '', 
          chinese: parts[1] ? parts[1].replace(/[\)）]$/, '').trim() : '' 
      };
  };

  const initial = parseInitial(selectedCell);
  const [tempAmis, setTempAmis] = useState(initial.amis);
  const [tempChinese, setTempChinese] = useState(initial.chinese);
  const [tempSound, setTempSound] = useState(selectedCell.sound || '');
  const [tempColor, setTempColor] = useState(selectedCell.color || '#bae6fd');
  const [tempImage, setTempImage] = useState(selectedCell.image || '');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleAiClick = async () => {
    if (!onAiGenerate || !tempAmis) return;
    setIsGenerating(true);
    const result = await onAiGenerate(tempAmis);
    if (result) {
        setTempImage(result);
    }
    setIsGenerating(false);
  };

  return (
    <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl p-6 w-full max-w-md shadow-2xl overflow-y-auto max-h-[90vh]">
        <div className="flex justify-between items-center mb-4 border-b pb-3">
             <h3 className="text-xl font-bold flex items-center gap-2 text-slate-800">
                <Edit3 className="w-5 h-5 text-blue-600"/> 編輯格位: {selectedCell.id.toUpperCase()}
            </h3>
            <button onClick={onClose} className="p-1 hover:bg-slate-100 rounded-full transition-colors">
                <X className="w-5 h-5 text-slate-400" />
            </button>
        </div>

        <div className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">族語單字 (第一層)</label>
                <input 
                  value={tempAmis} 
                  onChange={e => setTempAmis(e.target.value)}
                  className="w-full border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="例如: waco"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">中文意思 (第三層)</label>
                <input 
                  value={tempChinese} 
                  onChange={e => setTempChinese(e.target.value)}
                  className="w-full border rounded-lg p-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="例如: 狗"
                />
              </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1 flex items-center justify-between">
                <span className="flex items-center gap-1"><ImageIcon className="w-4 h-4"/> 圖片連結 (第二層)</span>
                {onAiGenerate && (
                    <button 
                        onClick={handleAiClick}
                        disabled={isGenerating || !tempAmis}
                        className="text-xs flex items-center gap-1 bg-gradient-to-r from-purple-500 to-pink-500 text-white px-2 py-1 rounded shadow hover:opacity-90 disabled:opacity-50 transition-all"
                    >
                        {isGenerating ? <Loader2 className="w-3 h-3 animate-spin"/> : <Wand2 className="w-3 h-3"/>}
                        AI 生成
                    </button>
                )}
            </label>
            <input 
              value={tempImage} 
              onChange={e => setTempImage(e.target.value)}
              className="w-full border rounded-lg p-2 text-xs font-mono bg-gray-50 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="https://... 或點擊上方按鈕生成"
            />
            {tempImage && (
                <div className="mt-2 w-full h-24 bg-gray-100 rounded flex items-center justify-center overflow-hidden border">
                    <img src={tempImage} alt="Preview" className="h-full object-contain" onError={(e) => (e.target as HTMLImageElement).src = 'https://placehold.co/400x300?text=Invalid+Image'}/>
                </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">背景顏色</label>
            <div className="flex gap-2 flex-wrap">
               {['#bae6fd', '#8d6e63', '#ffe8b3', '#fb8c00', '#e63946', '#f48fb1', '#66bb6a', '#ba68c8', '#fdd835', '#1e3a8a'].map(c => (
                   <button 
