                        </div>
                    ))}
                    {editedPlayers.length === 0 && (
                        <div className="flex flex-col items-center justify-center h-40 text-gray-400 border-2 border-dashed border-gray-200 rounded-xl">
                            <Users className="w-8 h-8 mb-2 opacity-50" />
                            <p>目前沒有玩家</p>
