                     // State 2 OR State 1 (but no image) -> Show Chinese
                     content = <span className={`font-bold drop-shadow-md text-center px-0.5 break-words w-full ${getFontSize(cell.chinese || "")}`} style={{ color: cell.textColor }}>{cell.chinese || cell.amis}</span>;
