                          <div className="absolute -top-6 -right-8 md:-top-3 md:-right-12 bg-yellow-400 text-amber-900 px-2 py-0.5 md:px-3 md:py-1 rounded-sm font-bold shadow-md transform rotate-12 z-20 border border-white text-[10px] md:text-sm whitespace-nowrap animate-bounce" style={{animationDuration: '2s'}}>
                              {currentDicePrompt}
