        }));
      }
    }, (error) => {
        if (error.code !== 'permission-denied' && error.code !== 'unavailable') {
             console.error("Firestore Error (Snapshot):", error);
        }
    });
    return () => unsubscribe();
  }, [user]);

  // Sync displayPlayers
